    {
      "tier_name": "Free Plan",
      "price": "Free",
      "features": [
        "Basic personalized study plan generation (limited scope/duration)",
        "Access to a subset of curated learning resources",
        "Limited progress tracking and basic feedback",
        "Standard user authentication & profile management"
      ]
    },
    {
      "tier_name": "Pro Plan",
      "price": "$19/month",
      "features": [
        "Unlimited personalized study plan generation with full adaptive capabilities",
        "Full access to curated and AI-generated learning resources (summaries, practice questions)",
        "Advanced progress tracking, in-depth analytics, and real-time adaptive plan adjustments",
        "Priority customer support",
        "Integration with common calendar applications"
      ]
    },
    {
      "tier_name": "Premium Plan",
      "price": "Custom",
      "features": [
        "All Pro Plan features",
        "Dedicated account manager",
        "Early access to new AI features and beta programs",
        "Option for institutional/group accounts with administrative dashboards",
        "Advanced API access for custom integrations (upon request)"
      ]
    }
  ],
  "gtm_strategy": "Our Go-to-Market strategy will focus on reaching self-learners and students directly through digital channels. We will launch with an initial beta program to gather early feedback and testimonials, then scale with targeted digital marketing. Key channels include: 1. Content Marketing & SEO: Creating valuable blog posts, study guides, and educational resources optimized for search engines to attract users seeking learning solutions and demonstrate the power of AI in education. 2. Targeted Social Media Marketing: Running ads and engaging in relevant educational communities on platforms like Reddit (r/study, r/learn), YouTube, and TikTok, showcasing the personalized study plan generation and progress tracking features with compelling short-form video content. 3. Educational Influencer Partnerships: Collaborating with popular education-focused YouTubers, TikTokers, and bloggers to review and promote the platform, leveraging their existing audience trust and reach.",
  "financial_metrics": {
    "breakeven_timeframe": "18-24 months post-launch, assuming consistent user acquisition and a conversion rate of 3-5% from free to Pro Plan.",
    "estimated_cost_structure": "Initial capital will primarily cover: 1. Personnel (AI engineers, backend/frontend developers, product manager): ~60-70%. 2. Cloud Infrastructure & AI Model Costs (Google Cloud Run, Cloud SQL, external AI APIs if used): ~15-20% (scaling with user base). 3. Marketing & User Acquisition (content creation, paid ads, influencer outreach): ~10-15%. 4. Software Licenses & Operational Tools: ~5%."
  }
}

